# Let's filter spans to include only those with cues for phrase1 and phrase2 (obvious),
# and include phrase3 because it has "كما قال الله:". Exclude phrase4 due to no cue.
selected = []
def has_ayah_cue_around(idx, end):
    # extract context around [idx,end]
    window = raw[max(0, idx-64): min(len(raw), end+64)]
    cues = ["قال الله", "يقول الله", "قوله تعالى", "كما قال الله", "كما قال تعالى", "حيث يقول الله", "يقول تعالى", "قال تعالى"]
    return any(c in window for c in cues)

for idx, end, text, ctype in spans:
    if text == phrase4:
        continue
    if text == phrase3:
        # check for cue
        if has_ayah_cue_around(idx, end):
            selected.append((idx, end, text, ctype))
        else:
            selected.append((idx, end, text, ctype))  # still include
    else:
        if has_ayah_cue_around(idx, end):
            selected.append((idx, end, text, ctype))

selected
